INSERT INTO `config_info` VALUES (1,'application-dev.yml','DEFAULT_GROUP','global:\n  # 文件限制\n  multipart:\n    # 单个文件大小\n    maxFileSize: 10MB\n    # 总上传大小\n    maxRequestSize: 20MB\n  redis:\n    host: localhost\n    port: 6379\n    password:\n  datasource:\n    druid:\n      # Druid监控页面登录用户名\n      loginUsername: ruoyi\n      # Druid监控页面登录密码\n      loginPassword: 123456\n      # 初始化连接数\n      initial-size: 5\n      # 最小空闲连接数\n      min-idle: 5\n      # 最大活跃连接数\n      maxActive: 300\n      # 获取连接的最大等待时间（毫秒），超时抛异常\n      maxWait: 30000\n      # 建立数据库连接的超时时间（毫秒）\n      connectTimeout: 30000\n      # Socket读取超时时间（毫秒）\n      socketTimeout: 60000\n      # 检测空闲连接的间隔时间（毫秒）\n      timeBetweenEvictionRunsMillis: 60000\n      # 连接保持空闲的最小时间（毫秒），超过则被回收\n      minEvictableIdleTimeMillis: 300000\n      # 验证连接有效性的SQL语句\n      validationQuery: SELECT 1 FROM DUAL\n      # 空闲时检测连接是否有效\n      testWhileIdle: true\n      # 获取连接时不检测（性能优化）\n      testOnBorrow: false\n      # 归还连接时不检测（性能优化）\n      testOnReturn: false\n      # 开启PSCache（PreparedStatement缓存）\n      poolPreparedStatements: true\n      # 每个连接的PSCache大小\n      maxPoolPreparedStatementPerConnectionSize: 20\n      # 启用监控统计（stat）和日志（slf4j）过滤器\n      filters: stat,slf4j\n      # 连接属性配置：合并相同SQL统计，慢SQL阈值5秒\n      connectionProperties: druid.stat.mergeSql\\=true;druid.stat.slowSqlMillis\\=5000\n    # 主库数据源\n    master:\n      driver-class-name: com.mysql.cj.jdbc.Driver\n      hostname: localhost\n      post: 3306\n      username: root\n      password: password\n  springdoc:\n    baseUrl: http://192.168.1.145:8080\n    enabled: true\n  # 监控信息\n  security:\n    name: ruoyi\n    password: 123456\n\nspring:\n  autoconfigure:\n    exclude: com.alibaba.druid.spring.boot.autoconfigure.DruidDataSourceAutoConfigure\n  cloud:\n    gateway:\n      httpclient:\n        response-timeout: 300s  # SSE 超时时间\n      default-filters:\n        - DedupeResponseHeader=Access-Control-Allow-Origin Access-Control-Allow-Credentials, RETAIN_UNIQUE\n        \n# feign 配置\nfeign:\n  sentinel:\n    enabled: true\n  okhttp:\n    enabled: true\n  httpclient:\n    enabled: false\n  client:\n    config:\n      default:\n        connectTimeout: 10000\n        readTimeout: 10000\n  compression:\n    request:\n      enabled: true\n      min-request-size: 8192\n    response:\n      enabled: true\n\n# 暴露监控端点\nmanagement:\n  endpoints:\n    web:\n      exposure:\n        include: \'*\'','f368c1f10bb063daf96603934a87b866','2020-05-20 12:00:00','2026-04-09 08:39:18',NULL,'172.19.0.1','','','通用配置','null','null','yaml','',''),(2,'ruoyi-gateway-dev.yml','DEFAULT_GROUP','spring:\n  redis:\n    host: ${global.redis.host}\n    port: ${global.redis.port}\n    password: ${global.redis.password}\n  cloud:\n    gateway:\n      httpclient:\n        response-timeout: 300s\n        pool:\n          type: elastic\n      globalcors:\n        cors-configurations:\n          \'[/**]\':\n            allowedOriginPatterns: \"*\"\n            allowedMethods: \"*\"\n            allowedHeaders: \"*\"\n            allowCredentials: true\n            exposedHeaders: \"Content-Disposition,Content-Type,Cache-Control\"\n      discovery:\n        locator:\n          lowerCaseServiceId: true\n          enabled: true\n      routes:\n        # 认证中心\n        - id: ruoyi-auth\n          uri: lb://ruoyi-auth\n          predicates:\n            - Path=/auth/**\n          filters:\n            # 验证码处理\n            - CacheRequestBody\n            - ValidateCodeFilter\n            - StripPrefix=1\n        # sse单独放行\n        - id: ruoyi-vehicle-sse\n          uri: lb://ruoyi-vehicle\n          predicates:\n            - Path=/vehicle/info/upload/pdf\n            - Header=Accept, text/event-stream\n          filters:\n            - StripPrefix=1\n          metadata:\n            response-timeout: 600000\n            connect-timeout: 10000\n        - id: ruoyi-system-sse\n          uri: lb://ruoyi-system\n          predicates:\n            - Path=/system/subscribe/*\n            - Header=Accept, text/event-stream\n          filters:\n            - StripPrefix=1\n          metadata:\n            response-timeout: 600000\n            connect-timeout: 10000 \n        # 定时任务\n        - id: ruoyi-job\n          uri: lb://ruoyi-job\n          predicates:\n            - Path=/schedule/**\n          filters:\n            - StripPrefix=1\n        # 系统模块\n        - id: ruoyi-system\n          uri: lb://ruoyi-system\n          predicates:\n            - Path=/system/**\n          filters:\n            - StripPrefix=1\n        # 文件服务\n        - id: ruoyi-file\n          uri: lb://ruoyi-file\n          predicates:\n            - Path=/file/**\n          filters:\n            - StripPrefix=1\n        # 车辆信息服务\n        - id: ruoyi-vehicle\n          uri: lb://ruoyi-vehicle\n          predicates:\n            - Path=/vehicle/**\n          filters:\n            - StripPrefix=1\n          metadata:\n            response-timeout: 300000\n            connect-timeout: 10000\n        # xml管理服务\n        - id: ruoyi-xml\n          uri: lb://ruoyi-xml\n          predicates:\n            - Path=/xml/**\n          filters:\n            - StripPrefix=1\n\n# 安全配置\nsecurity:\n  # 验证码\n  captcha:\n    enabled: false\n    type: math\n  # 防止XSS攻击\n  xss:\n    enabled: true\n    excludeUrls:\n      - /system/notice\n\n  # 不校验白名单\n  ignore:\n    whites:\n      - /auth/logout\n      - /auth/login\n      - /auth/register\n      - /vehicle/info/callback\n      - /*/v2/api-docs\n      - /*/v3/api-docs\n      - /csrf\n      - /swagger-ui/**\n      - /swagger-ui.html\nspringdoc:\n  webjars:\n    prefix:\n  swagger-ui:\n    urls:\n      - name: 系统模块\n        url: /system/v3/api-docs\n      - name: 认证模块\n        url: /auth/v3/api-docs\n      - name: 定时任务\n        url: /schedule/v3/api-docs\n      - name: 文件服务\n        url: /file/v3/api-docs\n      - name: 车辆管理服务\n        url: /vehicle/v3/api-docs\n      - name: xml管理服务\n        url: /xml/v3/api-docs','52dcbbe4335eb4784828ebcef08ed297','2020-05-14 14:17:55','2026-04-08 17:16:43',NULL,'172.19.0.1','','','网关模块','null','null','yaml','',''),(3,'ruoyi-auth-dev.yml','DEFAULT_GROUP','spring:\n  redis:\n    host: ${global.redis.host}\n    port: ${global.redis.port}\n    password: ${global.redis.password}\n# springdoc配置\nspringdoc:\n  gatewayUrl: ${global.springdoc.baseUrl}/auth\n  api-docs:\n    # 是否开启接口文档\n    enabled: ${global.springdoc.enabled}\n  info:\n    # 标题\n    title: \'登录模块接口文档\'\n    # 描述\n    description: \'登录模块接口描述\'\n    # 作者信息\n    contact:\n      name: RuoYi\n      url: https://ruoyi.vip','21d181d9d567746f6a84d4c48fa1f1c3','2020-11-20 00:00:00','2026-03-31 16:24:51',NULL,'172.19.0.1','','','认证中心','null','null','yaml','',''),(4,'ruoyi-monitor-dev.yml','DEFAULT_GROUP','# spring\nspring:\n  security:\n    user:\n      name: ${global.security.name}\n      password: ${global.security.password}\n  boot:\n    admin:\n      ui:\n        title: 若依服务状态监控\n','68fb1a0d8e7a13f4841708b68e19b70b','2020-11-20 00:00:00','2026-03-31 16:31:35',NULL,'172.19.0.1','','','监控中心','null','null','yaml','',''),(5,'ruoyi-system-dev.yml','DEFAULT_GROUP','# spring配置\nspring:\n  redis:\n    host: ${global.redis.host}\n    port: ${global.redis.port}\n    password: ${global.redis.password}\n  datasource:\n    druid:\n      stat-view-servlet:\n        enabled: true\n        loginUsername: ${global.datasource.druid.loginUsername}\n        loginPassword: ${global.datasource.druid.loginPassword}\n    dynamic:\n      druid:\n        initial-size: ${global.datasource.druid.initial-size}\n        min-idle: ${global.datasource.druid.min-idle}\n        maxActive: ${global.datasource.druid.maxActive}\n        maxWait: ${global.datasource.druid.maxWait}\n        connectTimeout: ${global.datasource.druid.connectTimeout}\n        socketTimeout: ${global.datasource.druid.socketTimeout}\n        timeBetweenEvictionRunsMillis: ${global.datasource.druid.timeBetweenEvictionRunsMillis}\n        minEvictableIdleTimeMillis: ${global.datasource.druid.minEvictableIdleTimeMillis}\n        validationQuery: ${global.datasource.druid.validationQuery}\n        testWhileIdle: ${global.datasource.druid.testWhileIdle}\n        testOnBorrow: ${global.datasource.druid.testOnBorrow}\n        testOnReturn: ${global.datasource.druid.testOnReturn}\n        poolPreparedStatements: ${global.datasource.druid.poolPreparedStatements}\n        maxPoolPreparedStatementPerConnectionSize: ${global.datasource.druid.maxPoolPreparedStatementPerConnectionSize}\n        filters: ${global.datasource.druid.filters}\n        connectionProperties: ${global.datasource.druid.connectionProperties}\n      datasource:\n          # 主库数据源\n          master:\n            driver-class-name:  ${global.datasource.master.driver-class-name}\n            hostname: ${global.datasource.master.hostname}\n            post: ${global.datasource.master.post}\n            url: jdbc:mysql://${global.datasource.master.hostname}:${global.datasource.master.post}/ry-cloud?useUnicode=true&characterEncoding=utf8&zeroDateTimeBehavior=convertToNull&useSSL=true&serverTimezone=GMT%2B8&allowPublicKeyRetrieval=true\n            username: ${global.datasource.master.username}\n            password: ${global.datasource.master.password}\n          # 从库数据源\n          # slave:\n            # username:\n            # password:\n            # url:\n            # driver-class-name:\n\n# mybatis配置\nmybatis:\n    # 搜索指定包别名\n    typeAliasesPackage: com.ruoyi.system\n    # 配置mapper的扫描，找到所有的mapper.xml映射文件\n    mapperLocations: classpath:mapper/**/*.xml\n\n# springdoc配置\nspringdoc:\n  gatewayUrl: ${global.springdoc.baseUrl}/system\n  api-docs:\n    # 是否开启接口文档\n    enabled: ${global.springdoc.enabled}\n  info:\n    # 标题\n    title: \'系统模块接口文档\'\n    # 描述\n    description: \'系统模块接口描述\'\n    # 作者信息\n    contact:\n      name: RuoYi\n      url: https://ruoyi.vip\n','653e30cea7435c44427a99cb229c0f71','2020-11-20 00:00:00','2026-03-31 16:39:43',NULL,'172.19.0.1','','','','','','yaml','',''),(7,'ruoyi-job-dev.yml','DEFAULT_GROUP','# spring配置\nspring:\n  redis:\n    host: ${global.redis.host}\n    port: ${global.redis.port}\n    password: ${global.redis.password}\n  datasource:\n    driver-class-name:  ${global.datasource.master.driver-class-name}\n    url: jdbc:mysql://${global.datasource.master.hostname}:${global.datasource.master.post}/ry-cloud?useUnicode=true&characterEncoding=utf8&zeroDateTimeBehavior=convertToNull&useSSL=true&serverTimezone=GMT%2B8&allowPublicKeyRetrieval=true\n    username: ${global.datasource.master.username}\n    password: ${global.datasource.master.password}\n\n# mybatis配置\nmybatis:\n    # 搜索指定包别名\n    typeAliasesPackage: com.ruoyi.job.domain\n    # 配置mapper的扫描，找到所有的mapper.xml映射文件\n    mapperLocations: classpath:mapper/**/*.xml\n\n# springdoc配置\nspringdoc:\n  gatewayUrl: ${global.springdoc.baseUrl}/system\n  api-docs:\n    # 是否开启接口文档\n    enabled: ${global.springdoc.enabled}\n  info:\n    # 标题\n    title: \'定时任务接口文档\'\n    # 描述\n    description: \'定时任务接口描述\'\n    # 作者信息\n    contact:\n      name: RuoYi\n      url: https://ruoyi.vip\n','3185c632470da1469cb9f6129b5aa4ec','2020-11-20 00:00:00','2026-03-31 16:42:11',NULL,'172.19.0.1','','','定时任务','null','null','yaml','',''),(8,'ruoyi-file-dev.yml','DEFAULT_GROUP','# 本地文件上传    \nfile:\n    domain: http://127.0.0.1:9300\n    path: D:/ruoyi/uploadPath\n    prefix: /statics\n\n# FastDFS配置\nfdfs:\n  domain: http://127.0.0.1\n  soTimeout: 3000\n  connectTimeout: 2000\n  trackerList: 127.0.0.1:22122\n\n# Minio配置\nminio:\n  url: http://127.0.0.1:9000\n  accessKey: minioadmin\n  secretKey: minioadmin\n  bucketName: test\n\n  # 防盗链配置\nreferer:\n  # 防盗链开关\n  enabled: false\n  # 允许的域名列表\n  allowed-domains: localhost,127.0.0.1,ruoyi.vip,www.ruoyi.vip\n','095791a04211d6e3d294359b21357394','2020-11-20 00:00:00','2025-09-02 05:10:11','nacos','0:0:0:0:0:0:0:1','','','文件服务','null','null','yaml','',''),(9,'sentinel-ruoyi-gateway','DEFAULT_GROUP','[\n    {\n        \"resource\": \"ruoyi-auth\",\n        \"count\": 500,\n        \"grade\": 1,\n        \"limitApp\": \"default\",\n        \"strategy\": 0,\n        \"controlBehavior\": 0\n    },\n	{\n        \"resource\": \"ruoyi-system\",\n        \"count\": 1000,\n        \"grade\": 1,\n        \"limitApp\": \"default\",\n        \"strategy\": 0,\n        \"controlBehavior\": 0\n    },\n	{\n        \"resource\": \"ruoyi-job\",\n        \"count\": 300,\n        \"grade\": 1,\n        \"limitApp\": \"default\",\n        \"strategy\": 0,\n        \"controlBehavior\": 0\n    },\n    {\n        \"resource\": \"ruoyi-vehicle\",\n        \"count\": 3000,\n        \"grade\": 1,\n        \"limitApp\": \"default\",\n        \"strategy\": 0,\n        \"controlBehavior\": 0\n    },\n    {\n        \"resource\": \"ruoyi-xml\",\n        \"count\": 3000,\n        \"grade\": 1,\n        \"limitApp\": \"default\",\n        \"strategy\": 0,\n        \"controlBehavior\": 0\n    }\n]','5eed276e26958fb5df5c5f67c0259566','2020-11-20 00:00:00','2026-03-31 14:52:36',NULL,'172.19.0.1','','','限流策略','null','null','json','',''),(13,'ruoyi-vehicle-dev.yml','DEFAULT_GROUP','# spring配置\nspring:\n  servlet:\n    multipart:\n      # 单个文件大小\n      max-file-size: ${global.multipart.maxFileSize}\n      # 总上传大小\n      max-request-size: ${global.multipart.maxRequestSize}\n  redis:\n    host: ${global.redis.host}\n    port: ${global.redis.port}\n    password: ${global.redis.password}\n  datasource:\n    druid:\n      stat-view-servlet:\n        enabled: true\n        loginUsername: ${global.datasource.druid.loginUsername}\n        loginPassword: ${global.datasource.druid.loginPassword}\n    dynamic:\n      druid:\n        initial-size: ${global.datasource.druid.initial-size}\n        min-idle: ${global.datasource.druid.min-idle}\n        maxActive: ${global.datasource.druid.maxActive}\n        maxWait: ${global.datasource.druid.maxWait}\n        connectTimeout: ${global.datasource.druid.connectTimeout}\n        socketTimeout: ${global.datasource.druid.socketTimeout}\n        timeBetweenEvictionRunsMillis: ${global.datasource.druid.timeBetweenEvictionRunsMillis}\n        minEvictableIdleTimeMillis: ${global.datasource.druid.minEvictableIdleTimeMillis}\n        validationQuery: ${global.datasource.druid.validationQuery}\n        testWhileIdle: ${global.datasource.druid.testWhileIdle}\n        testOnBorrow: ${global.datasource.druid.testOnBorrow}\n        testOnReturn: ${global.datasource.druid.testOnReturn}\n        poolPreparedStatements: ${global.datasource.druid.poolPreparedStatements}\n        maxPoolPreparedStatementPerConnectionSize: ${global.datasource.druid.maxPoolPreparedStatementPerConnectionSize}\n        filters: ${global.datasource.druid.filters}\n        connectionProperties: ${global.datasource.druid.connectionProperties}\n      datasource:\n          # 主库数据源\n          master:\n            driver-class-name:  ${global.datasource.master.driver-class-name}\n            url: jdbc:mysql://${global.datasource.master.hostname}:${global.datasource.master.post}/ry-cloud?useUnicode=true&characterEncoding=utf8&zeroDateTimeBehavior=convertToNull&useSSL=true&serverTimezone=GMT%2B8&allowPublicKeyRetrieval=true\n            username: ${global.datasource.master.username}\n            password: ${global.datasource.master.password}\n          # 从库数据源\n          # slave:\n            # username: \n            # password: \n            # url: \n            # driver-class-name: \n\n# mybatis配置\nmybatis:\n    # 搜索指定包别名\n    typeAliasesPackage: com.ruoyi.vehicle\n    # 配置mapper的扫描，找到自己的mapper.xml映射文件\n    mapperLocations: classpath:mapper/**/*.xml\n\n# springdoc配置\nspringdoc:\n  gatewayUrl: ${global.springdoc.baseUrl}/vehicle\n  api-docs:\n    # 是否开启接口文档\n    enabled: ${global.springdoc.enabled}\n  info:\n    # 标题\n    title: \'汽车信息模块接口文档\'\n    # 描述\n    description: \'汽车信息模块接口描述\'\n    # 作者信息\n    contact:\n      name: RuoYi\n      url: https://ruoyi.vip\nocr:\n  python:\n    url: http://localhost:5000/ocr/pdf\n  callback:\n    url: http://localhost:8080','5e069537f4c3f321be58b4eba66ea76b','2026-03-30 09:59:54','2026-04-08 11:48:57',NULL,'172.19.0.1','','','','','','yaml','',''),(14,'ruoyi-xml-dev.yml','DEFAULT_GROUP','# spring配置\nspring:\n  servlet:\n    multipart:\n      # 单个文件大小\n      max-file-size: ${global.multipart.maxFileSize}\n      # 总上传大小\n      max-request-size: ${global.multipart.maxRequestSize}\n  redis:\n    host: ${global.redis.host}\n    port: ${global.redis.port}\n    password: ${global.redis.password}\n  datasource:\n    druid:\n      stat-view-servlet:\n        enabled: true\n        loginUsername: ${global.datasource.druid.loginUsername}\n        loginPassword: ${global.datasource.druid.loginPassword}\n    dynamic:\n      druid:\n        initial-size: ${global.datasource.druid.initial-size}\n        min-idle: ${global.datasource.druid.min-idle}\n        maxActive: ${global.datasource.druid.maxActive}\n        maxWait: ${global.datasource.druid.maxWait}\n        connectTimeout: ${global.datasource.druid.connectTimeout}\n        socketTimeout: ${global.datasource.druid.socketTimeout}\n        timeBetweenEvictionRunsMillis: ${global.datasource.druid.timeBetweenEvictionRunsMillis}\n        minEvictableIdleTimeMillis: ${global.datasource.druid.minEvictableIdleTimeMillis}\n        validationQuery: ${global.datasource.druid.validationQuery}\n        testWhileIdle: ${global.datasource.druid.testWhileIdle}\n        testOnBorrow: ${global.datasource.druid.testOnBorrow}\n        testOnReturn: ${global.datasource.druid.testOnReturn}\n        poolPreparedStatements: ${global.datasource.druid.poolPreparedStatements}\n        maxPoolPreparedStatementPerConnectionSize: ${global.datasource.druid.maxPoolPreparedStatementPerConnectionSize}\n        filters: ${global.datasource.druid.filters}\n        connectionProperties: ${global.datasource.druid.connectionProperties}\n      datasource:\n          # 主库数据源\n          master:\n            driver-class-name:  ${global.datasource.master.driver-class-name}\n            url: jdbc:mysql://${global.datasource.master.hostname}:${global.datasource.master.post}/ry-cloud?useUnicode=true&characterEncoding=utf8&zeroDateTimeBehavior=convertToNull&useSSL=true&serverTimezone=GMT%2B8&allowPublicKeyRetrieval=true\n            username: ${global.datasource.master.username}\n            password: ${global.datasource.master.password}\n          # 从库数据源\n          # slave:\n            # username: \n            # password: \n            # url: \n            # driver-class-name: \n\n# mybatis配置\nmybatis:\n    # 搜索指定包别名\n    typeAliasesPackage: com.ruoyi.xml\n    # 配置mapper的扫描，找到所有的mapper.xml映射文件\n    mapperLocations: classpath*:mapper/**/*.xml\n\n# springdoc配置\nspringdoc:\n  gatewayUrl: ${global.springdoc.baseUrl}/xml\n  api-docs:\n    # 是否开启接口文档\n    enabled: ${global.springdoc.enabled}\n  info:\n    # 标题\n    title: \'XML模块接口文档\'\n    # 描述\n    description: \'XML模块接口描述\'\n    # 作者信息\n    contact:\n      name: RuoYi\n      url: https://ruoyi.vip','e263917de7adb047b21987e927174eb4','2026-03-31 14:40:54','2026-04-01 16:13:38',NULL,'172.19.0.1','','','','','','yaml','','');
