llowedMethods: \"*\"\n            allowedHeaders: \"*\"\n            allowCredentials: true\n            exposedHeaders: \"Content-Disposition,Content-Type,Cache-Control\"\n      discovery:\n        locator:\n          lowerCaseServiceId: true\n          enabled: true\n      routes:\n        # 认证中心\n        - id: ruoyi-auth\n          uri: lb://ruoyi-auth\n          predicates:\n            - Path=/auth/**\n          filters:\n            # 验证码处理\n            - CacheRequestBody\n            - ValidateCodeFilter\n            - StripPrefix=1\n        # 定时任务\n        - id: ruoyi-job\n          uri: lb://ruoyi-job\n          predicates:\n            - Path=/schedule/**\n          filters:\n            - StripPrefix=1\n        # 系统模块\n        - id: ruoyi-system\n          uri: lb://ruoyi-system\n          predicates:\n            - Path=/system/**\n          filters:\n            - StripPrefix=1\n        # 文件服务\n        - id: ruoyi-file\n          uri: lb://ruoyi-file\n          predicates:\n            - Path=/file/**\n          filters:\n            - StripPrefix=1\n        # 车辆信息服务\n        - id: ruoyi-vehicle\n          uri: lb://ruoyi-vehicle\n          predicates:\n            - Path=/vehicle/**\n          filters:\n            - StripPrefix=1\n        # xml管理服务\n        - id: ruoyi-xml\n          uri: lb://ruoyi-xml\n          predicates:\n            - Path=/xml/**\n          filters:\n            - StripPrefix=1\n\n# 安全配置\nsecurity:\n  # 验证码\n  captcha:\n    enabled: false\n    type: math\n  # 防止XSS攻击\n  xss:\n    enabled: true\n    excludeUrls:\n      - /system/notice\n\n  # 不校验白名单\n  ignore:\n    whites:\n      - /auth/logout\n      - /auth/login\n      - /auth/register\n      - /*/v2/api-docs\n      - /*/v3/api-docs\n      - /csrf\n      - /swagger-ui/**\n      - /swagger-ui.html\nspringdoc:\n  webjars:\n    prefix:\n  swagger-ui:\n    urls:\n      - name: 系统模块\n        url: /system/v3/api-docs\n      - name: 认证模块\n        url: /auth/v3/api-docs\n      - name: 定时任务\n        url: /schedule/v3/api-docs\n      - name: 文件服务\n        url: /file/v3/api-docs\n      - name: 车辆管理服务\n        url: /vehicle/v3/api-docs\n      - name: xml管理服务\n        url: /xml/v3/api-docs','6aab5aeb9b028a9951af6e20c295e4d3','2026-03-31 16:29:32','2026-03-31 08:29:32',NULL,'172.19.0.1','U','','','formal',NULL,NULL),(1,75,'application-dev.yml','DEFAULT_GROUP','','global:\n  # 文件限制\n  multipart:\n    # 单个文件大小\n    maxFileSize: 10MB\n    # 总上传大小\n    maxRequestSize: 20MB\n  redis:\n    host: localhost\n    port: 6379\n    password:\n  datasource:\n    druid:\n      loginUsername: ruoyi\n      loginPassword: 123456\n      initial-size: 5\n      min-idle: 5\n      maxActive: 20\n      maxWait: 60000\n      connectTimeout: 30000\n      socketTimeout: 60000\n      timeBetweenEvictionRunsMillis: 60000\n      minEvictableIdleTimeMillis: 300000\n      validationQuery: SELECT 1 FROM DUAL\n      testWhileIdle: true\n      testOnBorrow: false\n      testOnReturn: false\n      poolPreparedStatements: true\n      maxPoolPreparedStatementPerConnectionSize: 20\n      filters: stat,slf4j\n      connectionProperties: druid.stat.mergeSql\\=true;druid.stat.slowSqlMillis\\=5000\n    # 主库数据源\n    master:\n      driver-class-name: com.mysql.cj.jdbc.Driver\n      url: jdbc:mysql://localhost:3306/ry-cloud?useUnicode=true&characterEncoding=utf8&zeroDateTimeBehavior=convertToNull&useSSL=true&serverTimezone=GMT%2B8&allowPublicKeyRetrieval=true\n      username: root\n      password: password\n  springdoc:\n    baseUrl: http://192.168.1.132:8080\n    enabled: true\n\nspring:\n  autoconfigure:\n    exclude: com.alibaba.druid.spring.boot.autoconfigure.DruidDataSourceAutoConfigure\n\n# feign 配置\nfeign:\n  sentinel:\n    enabled: true\n  okhttp:\n    enabled: true\n  httpclient:\n    enabled: false\n  client:\n    config:\n      default:\n        connectTimeout: 10000\n        readTimeout: 10000\n  compression:\n    request:\n      enabled: true\n      min-request-size: 8192\n    res