  filters:\n            # 验证码处理\n            - CacheRequestBody\n            - ValidateCodeFilter\n            - StripPrefix=1\n        # sse单独放行\n        - id: ruoyi-vehicle-sse\n          uri: lb://ruoyi-vehicle\n          predicates:\n            - Path=/vehicle/info/upload/pdf\n            - Header=Accept, text/event-stream\n          filters:\n            - StripPrefix=1\n          metadata:\n            response-timeout: 600000\n            connect-timeout: 10000\n        - id: ruoyi-system-sse\n          uri: lb://ruoyi-system\n          predicates:\n            - Path=/system/subscribe/*\n            - Header=Accept, text/event-stream\n          filters:\n            - StripPrefix=1\n          metadata:\n            response-timeout: 600000\n            connect-timeout: 10000 \n        # 定时任务\n        - id: ruoyi-job\n          uri: lb://ruoyi-job\n          predicates:\n            - Path=/schedule/**\n          filters:\n            - StripPrefix=1\n        # 系统模块\n        - id: ruoyi-system\n          uri: lb://ruoyi-system\n          predicates:\n            - Path=/system/**\n          filters:\n            - StripPrefix=1\n        # 文件服务\n        - id: ruoyi-file\n          uri: lb://ruoyi-file\n          predicates:\n            - Path=/file/**\n          filters:\n            - StripPrefix=1\n        # 车辆信息服务\n        - id: ruoyi-vehicle\n          uri: lb://ruoyi-vehicle\n          predicates:\n            - Path=/vehicle/**\n          filters:\n            - StripPrefix=1\n          metadata:\n            response-timeout: 300000\n            connect-timeout: 10000\n        # xml管理服务\n        - id: ruoyi-xml\n          uri: lb://ruoyi-xml\n          predicates:\n            - Path=/xml/**\n          filters:\n            - StripPrefix=1\n\n# 安全配置\nsecurity:\n  # 验证码\n  captcha:\n    enabled: false\n    type: math\n  # 防止XSS攻击\n  xss:\n    enabled: true\n    excludeUrls:\n      - /system/notice\n      - /sysem/subscribe\n      - /vehicle/info/upload/pdf\n      - /xml\n\n  # 不校验白名单\n  ignore:\n    whites:\n      - /auth/logout\n      - /auth/login\n      - /auth/register\n      - /vehicle/info/callback\n      - /*/v2/api-docs\n      - /*/v3/api-docs\n      - /csrf\n      - /swagger-ui/**\n      - /swagger-ui.html\nspringdoc:\n  webjars:\n    prefix:\n  swagger-ui:\n    urls:\n      - name: 系统模块\n        url: /system/v3/api-docs\n      - name: 认证模块\n        url: /auth/v3/api-docs\n      - name: 定时任务\n        url: /schedule/v3/api-docs\n      - name: 文件服务\n        url: /file/v3/api-docs\n      - name: 车辆管理服务\n        url: /vehicle/v3/api-docs\n      - name: xml管理服务\n        url: /xml/v3/api-docs','c83a4c452e09bd3bbdd1d016dca4b287','2026-04-08 17:16:43','2026-04-08 09:16:43',NULL,'172.19.0.1','U','','','formal',NULL,NULL),(1,119,'application-dev.yml','DEFAULT_GROUP','','global:\n  # 文件限制\n  multipart:\n    # 单个文件大小\n    maxFileSize: 10MB\n    # 总上传大小\n    maxRequestSize: 20MB\n  redis:\n    host: localhost\n    port: 6379\n    password:\n  datasource:\n    druid:\n      # Druid监控页面登录用户名\n      loginUsername: ruoyi\n      # Druid监控页面登录密码\n      loginPassword: 123456\n      # 初始化连接数\n      initial-size: 5\n      # 最小空闲连接数\n      min-idle: 5\n      # 最大活跃连接数\n      maxActive: 300\n      # 获取连接的最大等待时间（毫秒），超时抛异常\n      maxWait: 30000\n      # 建立数据库连接的超时时间（毫秒）\n      connectTimeout: 30000\n      # Socket读取超时时间（毫秒）\n      socketTimeout: 60000\n      # 检测空闲连接的间隔时间（毫秒）\n      timeBetweenEvictionRunsMillis: 60000\n      # 连接保持空闲的最小时间（毫秒），超过则被回收\n      minEvictableIdleTimeMillis: 300000\n      # 验证连接有效性的SQL语句\n      validationQuery: SELECT 1 FROM DUAL\n      # 空闲时检测连接是否有效\n      testWhileIdle: true\n      # 获取连接时不检测（性能优化）\n      testOnBorrow: false\n      # 归还连接时不检测（性能优化）\n      testOnReturn: false\n      # 开启PSCache（PreparedStatement缓存）\n      poolPreparedStatements: true\n      # 每个连接的PSCache大小\n      maxPoolPreparedStatementPerConnectionSize: 20\n      # 启用监控统计（stat）和日志（slf4j）过滤器\n      filters: stat,slf4j\n      # 连接属性配置：合并相同SQL统计，慢SQL阈值5秒\n      connectionProperties: druid.stat.mergeSql\\=true;druid.stat.slowSqlMillis\\=5000\n    # 主库数据源\n    master:\n      driver-class-name: com.mysql.cj.jdbc.Driver\n      hostname: localhost\n      post: 3306\n      username: root\n      password: password\n  springdoc:\n    baseUrl: http://192.168.1.142:8080\n    enabled: true\n  # 监控信息\n  security:\n    name: ruoyi\n    password: 123456\n\nspring:\n  autoconfigure:\n    exclude: com.alibaba.druid.spring.boot.autoconfigure.DruidDataSourceAutoConfigure\n  cloud:\n    gateway:\n      httpclient:\n        response-timeout: 300s  # SSE 超时时间\n      default-filters:\n        - DedupeResponseHeader=Access-Control-Allow-Origin Access-Control-Allow-Credentials, RETAIN_UNIQUE\n        \n# feign 配置\nfeign:\n  sentinel:\n    enabled: true\n  okhttp:\n    enabled: true\n  httpclient:\n    enabled: false\n  client:\n    config:\n      default:\n        connectTimeout: 10000\n        readTimeout: 10000\n  compression:\n    request:\n      enabled: true\n      min-request-size: 8192\n    response:\n      enabled: true\n\n# 暴露监控端点\nmanagement:\n  endpoints:\n    web:\n      exposure:\n        include: \'*\'','59eedbf0693b48f376bbf8828f9d7109','2026-04-09 08:39:18','2026-04-09 00:39:18',NULL,'172.19.0.1','U','','','formal',NULL,NULL);
